#nullable enable // autogenerated

using UnityEngine;

namespace MVZ2.UI
{
    public class OptionsDialog : Dialog
    {
        public Camera? GetCamera()
        {
            return canvasCamera;
        }
        public void SetPage(Page page)
        {
            mainPage.gameObject.SetActive(page == Page.Main);
            morePage.gameObject.SetActive(page == Page.More);
        }

        #region 生命周期
        private void Awake()
        {
            var rectTrans = transform as RectTransform;
            if (rectTrans.Exists())
            {
                var rootCanvas = rectTrans.GetRootCanvas();
                if (rootCanvas.Exists())
                {
                    canvasCamera = rootCanvas.worldCamera;
                }
            }
        }
        #endregion

        public OptionsDialogMainPage Main => mainPage;
        public OptionsDialogMoreOptionsPage MoreOptions => morePage;
        private Camera? canvasCamera;

        [Header("Pages")]
        [SerializeField]
        private OptionsDialogMainPage mainPage = null!;
        [SerializeField]
        private OptionsDialogMoreOptionsPage morePage = null!;

        public enum Page
        {
            Main,
            More
        }
    }
}
